// Shop.js
import React, { useEffect, useState } from "react";
import "../index.css";
import { Link } from "react-router-dom";
import axios from "axios";

const Shop = () => {
  const [products, setProducts] = useState([]);

  useEffect(() => {
    axios
      .get("http://localhost:5000/api/products") // 👈 your backend endpoint
      .then((res) => setProducts(res.data))
      .catch((err) => console.error("Error fetching products:", err));
  }, []);

  return (
    <div className="products-container">
      <h2 className="section-title">All Products</h2>
      <div className="products-grid">
        {products.map((product) => (
          <div className="product-card" key={product._id}>
            <Link to={'/product/${product._id}'}>
              <div className="product-img">
                <img src={product.image} alt={product.name} />
              </div>
            </Link>
            <h3 className="product-name">{product.name}</h3>
            <p className="product-desc">{product.description}</p>
            <div className="product-rating">
              {Array.from({ length: 5 }, (_, i) => (
                <span
                  key={i}
                  className={i < Math.floor(product.rating || 0) ? "star filled" : "star"}
                >
                  ★
                </span>
              ))}
              <span className="rating-value">{product.rating || "N/A"}</span>
            </div>

            {/* ✅ Updated footer section */}
            <div className="product-footer">
              <span className="product-price">₹{product.price}</span>

              <div className="footer-buttons">
                {/* Add to Cart button */}
                <button className="cart-btn">Add to Cart</button>

                {/* Buy Now button (goes to ProductDetails) */}
                <Link to={'/product/${product._id}'}>
                  <button className="buy-btn">Buy Now</button>
                </Link>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Shop;
